{
    "level": "A1–B1",
    "intro": "In this section you will learn <strong>different types of interrogative sentences</strong> in the English language: from simple general questions to complex questions.",
    "rules": [
        {
            "label": "Yes/No Questions",
            "color": "emerald",
            "text": "<strong>General questions</strong> - the answer is "yes" or "no":",
            "example": "Do you like coffee?"
        },
        {
            "label": "Wh-Questions",
            "color": "blue",
            "text": "<strong>Special questions</strong> - with question words:",
            "example": "What do you want?"
        },
        {
            "label": "Question Tags",
            "color": "rose",
            "text": "<strong>Chapter questions</strong> — for confirmation:",
            "example": "You like tea, don't you?"
        }
    ]
}
